function buscarLeyes(termino, materia) {
    const terminoLower = termino.toLowerCase();
    return leyesMexicanas.filter((ley)=>{
        const coincideMateria = !materia || ley.materia.toLowerCase() === materia.toLowerCase();
        const coincideTermino = ley.titulo.toLowerCase().includes(terminoLower) || ley.abreviatura.toLowerCase().includes(terminoLower) || ley.articulos.some((a)=>a.contenido.toLowerCase().includes(terminoLower) || a.numero.includes(termino));
        return coincideMateria && coincideTermino;
    });
}
function buscarArticulo(leyId, numero) {
    const ley = leyesMexicanas.find((l)=>l.id === leyId);
    return ley?.articulos.find((a)=>a.numero === numero);
}
function buscarJurisprudencia(termino, materia) {
    const terminoLower = termino.toLowerCase();
    return jurisprudencias.filter((j)=>{
        const coincideMateria = !materia || j.materia.toLowerCase() === materia.toLowerCase();
        const coincideTermino = j.titulo.toLowerCase().includes(terminoLower) || j.tesis.toLowerCase().includes(terminoLower) || j.aplicacion.toLowerCase().includes(terminoLower);
        return coincideMateria && coincideTermino;
    });
}
